  filter:blur(70px);
  pointer-events:none;
  opacity:.35;
}
.orb-1{width:240px;height:240px;background:#4c83ff;top:40px;left:30px}
.orb-2{width:260px;height:260px;background:#7b5cff;right:40px;bottom:50px}

.app-shell{
  position:relative;
  max-width:1400px;
  margin:0 auto;
  padding:28px;
}

.hero{
  display:flex;
  justify-content:space-between;
  align-items:flex-end;
  gap:24px;
  margin-bottom:22px;
}
.hero h1{
  margin:10px 0 12px;
  font-size:clamp(2rem, 5vw, 3.6rem);
  line-height:1;
  letter-spacing:-.04em;
}
.hero h1 span{
  background:linear-gradient(90deg,#8ab4ff,#c0a8ff);
  -webkit-background-clip:text;
  background-clip:text;
  color:transparent;
}
.hero p{
  margin:0;
  max-width:760px;
  color:var(--muted);
  line-height:1.6;
}
.pill{
  display:inline-flex;
  padding:8px 14px;
  border:1px solid rgba(255,255,255,.14);
  border-radius:999px;
  background:rgba(255,255,255,.06);
  color:#d8e5ff;
  font-size:.85rem;
}

.hero-actions{display:flex;gap:12px;flex-wrap:wrap}
.btn{
  border:none;
  border-radius:16px;
  padding:14px 18px;
  font-weight:700;
  cursor:pointer;
  transition:.2s ease;
}
.btn:hover{transform:translateY(-1px)}
.btn-primary{
  color:white;
  background:linear-gradient(135deg,var(--primary),var(--primary-2));
  box-shadow:0 12px 30px rgba(91,140,255,.35);
}
.btn-secondary{
  color:var(--text);
  background:rgba(255,255,255,.06);
  border:1px solid rgba(255,255,255,.12);
}

.top-summary{
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:18px;
  margin-bottom:18px;
}

.summary-card{
  padding:22px;
  border-radius:24px;
  box-shadow:var(--shadow);
  backdrop-filter: blur(14px);
  border:1px solid rgba(255,255,255,.12);
}
.summary-clt{background:linear-gradient(180deg,rgba(35,209,139,.18),rgba(255,255,255,.04))}
.summary-pj{background:linear-gradient(180deg,rgba(91,140,255,.18),rgba(255,255,255,.04))}
.summary-diff{background:linear-gradient(180deg,rgba(255,203,87,.20),rgba(255,255,255,.04))}
.summary-label{font-size:.9rem;color:#d7e3ff;opacity:.9}
.summary-value{font-size:clamp(1.8rem,3vw,2.8rem);font-weight:800;margin:10px 0}
.summary-sub{font-size:.92rem;color:var(--muted)}

.content-grid{
  display:grid;
  grid-template-columns:360px 1fr;
  gap:18px;
}

.glass{
  background:var(--panel);
  border:1px solid var(--panel-border);
  border-radius:var(--radius);
  backdrop-filter: blur(16px);
  box-shadow:var(--shadow);
}

.panel{padding:18px}
.panel-header{
  display:flex;
  justify-content:space-between;
  align-items:flex-start;
  gap:14px;
  margin-bottom:16px;
}
.panel-header h2{
  margin:0 0 4px;
  font-size:1.1rem;
}
.panel-header p{
  margin:0;
  color:var(--muted);
  font-size:.92rem;
}
.live-badge{
  padding:8px 12px;
  font-size:.82rem;
  border-radius:999px;
  background:rgba(35,209,139,.14);
  color:#8ff3c8;
  border:1px solid rgba(35,209,139,.24);
}

.tabs{display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap}
.tab{
  border:none;
  padding:10px 14px;
  border-radius:14px;
  background:rgba(255,255,255,.06);
  color:var(--text);
  cursor:pointer;
  font-weight:600;
}
.tab.active{
  background:linear-gradient(135deg,var(--primary),var(--primary-2));
}
.tab-content{display:none}
.tab-content.active{display:block}

.field{display:flex;flex-direction:column;gap:8px;margin-bottom:14px}
.field span{font-size:.9rem;color:#dce7ff}
.field input{
  width:100%;
  border:none;
  outline:none;
  padding:14px 15px;
  border-radius:16px;
  background:rgba(255,255,255,.08);
  color:var(--text);
  border:1px solid rgba(255,255,255,.10);
