  display:grid;
  grid-template-columns:1fr 1fr;
  gap:12px;
}
.switch{
  display:flex;
  align-items:center;
  gap:12px;
  color:#dce7ff;
  background:rgba(255,255,255,.05);
  padding:14px 16px;
  border-radius:16px;
  margin-top:8px;
}
.switch input{accent-color:#7b5cff}

.dashboard{display:flex;flex-direction:column;gap:18px}
.row{display:grid;gap:18px}
.row-2{grid-template-columns:1fr 1fr}

.compare-bars{display:flex;flex-direction:column;gap:16px;margin-top:10px}
.bar-item{display:flex;flex-direction:column;gap:8px}
.bar-top{display:flex;justify-content:space-between;gap:14px}
.bar-top span{color:#c7d6f6}
.bar-track{
  width:100%;
  height:16px;
  border-radius:999px;
  background:rgba(255,255,255,.08);
  overflow:hidden;
}
