}
.bar-fill.clt{background:linear-gradient(90deg,#23d18b,#78ffbb)}
.bar-fill.pj{background:linear-gradient(90deg,#5b8cff,#a98dff)}

.winner-box{
  margin-top:18px;
  padding:16px 18px;
  border-radius:18px;
