  line-height:1.5;
}

.mini-metrics{
  display:grid;
  grid-template-columns:1fr 1fr;
  gap:12px;
  margin-bottom:18px;
}
.metric{
  padding:14px;
  border-radius:18px;
  background:rgba(255,255,255,.05);
  border:1px solid rgba(255,255,255,.08);
}
.metric span{display:block;font-size:.86rem;color:var(--muted);margin-bottom:6px}
.metric strong{font-size:1.05rem}

.gauge-wrap{
  display:flex;
