    conic-gradient(#23d18b calc(var(--value) * 1%), rgba(255,255,255,.08) 0);
  display:grid;
  place-items:center;
  transition:all .4s ease;
}
.gauge-inner{
  width:132px;
  height:132px;
  border-radius:50%;
  background:linear-gradient(180deg, rgba(8,17,31,.96), rgba(18,28,48,.96));
  border:1px solid rgba(255,255,255,.08);
  display:flex;
  flex-direction:column;
  align-items:center;
